window.__QUIZ_DATA__=[{"id":"objective>Data Processing>2025>1","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : HISTORY OF COMPUTERS","question":"The  Difference Engine  was developed by","images":[],"options":{"A":"Blaise Pascal.","B":"Charles Babbage.","C":"Herman Hollerith.","D":"John Von Neumann."},"answer":"B","explanation":"The Difference Engine was designed by Charles Babbage in the early 19th century (1820s). It was a mechanical calculator intended to automate polynomial calculations (e.g., for navigation tables), eliminating human errors.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>2","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Convert A0BHEX\u200b to a number in binary.","images":[],"options":{"A":"1010010112","B":"1011010102","C":"1010000010112","D":"1011000010102"},"answer":"C","explanation":"Breaking down each hexadecimal digit into its 4-bit binary equivalent:    Hexadecimal digits (0-F) correspond to the following binary values:    Hex\tBinary0\t00001\t00012\t00103\t00114\t01005\t01016\t01107\t01118\t10009\t1001A\t1010B\t1011C\t1100D\t1101E\t1110F\t1111  Converting each digit of A0BHEX:    A \u2192 1010    0 \u2192 0000    B \u2192 1011    Combining the binary digits in order:    &nbsp;&nbsp;&nbsp;&nbsp;A&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;   0&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;   B  1010 0000 1011    Result: 101000001011\u2082","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>3","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Audio data are produced from","images":[],"options":{"A":"animations.","B":"graphics.","C":"pictures.","D":"sounds."},"answer":"D","explanation":"Audio data by its very definition refers to data that represents sound. It is created by capturing, digitizing, and storing sound waves.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>4","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Which of the following variables is an example of numeric data?","images":[],"options":{"A":"568","B":"B2","C":"\u20a610.00","D":"Twenty-five"},"answer":"A","explanation":"568 is a pure number \u2014 an example of numeric data.    B2 is alphanumeric (a mix of letter and number).    \u20a610.00 includes a currency symbol, so it's not strictly numeric.    Twenty-five is a textual (string) representation of a number.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>5","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : HISTORY OF COMPUTERS","question":"The generation of computers in which transistor was first introduced is the","images":[],"options":{"A":"fifth generation.","B":"fourth generation.","C":"second generation.","D":"third generation."},"answer":"C","explanation":"First generation computers used vacuum tubes.    Second generation computers introduced transistors, replacing vacuum tubes \u2014 this made computers smaller, faster, and more reliable.    Third generation used integrated circuits (ICs).    Fourth generation used microprocessors.    Fifth generation is based on artificial intelligence and advanced parallel processing.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>6","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"One application of  ICT  in medicine is","images":[],"options":{"A":"Computer Aided Learning.","B":"Computer Aided Manufacturing.","C":"Computerized Axial Tomography.","D":"Optical Character Recognition."},"answer":"C","explanation":"Computerized Axial Tomography (CAT), more commonly known as CT scans, is a medical imaging technique that uses X-rays and computer processing to create cross-sectional images (slices) of bones, blood vessels, and soft tissues inside your body. This is a direct and significant application of Information and Communication Technology (ICT) in medicine.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>7","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"Which one of the following reasons justifies the prevalence of Personal Digital Assistance devices? They","images":[],"options":{"A":"are lightweight and very expensive.","B":"are very portable and can be used everywhere.","C":"have limited capabilities compared to desktop and laptop computers.","D":"have small keyboards for input operation."},"answer":"B","explanation":"Personal Digital Assistants (PDAs), while somewhat superseded by smartphones now, were designed specifically for portability. Their primary appeal was their compact size, allowing users to carry them easily and access information, schedules, and basic applications on the go, virtually anywhere.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>8","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Which one of the following actions can be achieved by right-clicking a computer mouse?","images":[],"options":{"A":"Closing of the current windows","B":"Display of dialog box","C":"Minimizing of active windows","D":"Opening of contextual menus"},"answer":"D","explanation":"When you right-click a mouse on most operating systems (like Windows or macOS), it brings up a contextual menu \u2014 a list of options relevant to the object or area where the click occurred (e.g., desktop, file, or hyperlink).","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>9","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"The manipulation of digitized information by computer or other digital electronic equipment is known as:","images":[],"options":{"A":"data collation.","B":"data mining.","C":"information gathering.","D":"information processing."},"answer":"D","explanation":"Information processing refers to the manipulation, organization, and analysis of digitized data using computers or digital devices. It encompasses:    Input: Capturing data (e.g., via keyboards, sensors).    Processing: Transforming data (e.g., calculations, sorting).    Output: Presenting results (e.g., reports, visualizations).    Storage: Saving data for future use.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>10","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Which one of the following statements does not explain information processing?","images":[],"options":{"A":"Act of saving documents","B":"Changing of information detectable by an observer","C":"Conversion of raw data into information","D":"Process that describes everything that happens to a piece of information"},"answer":"A","explanation":"Information processing involves transforming or manipulating data to produce meaningful output. While saving documents is part of data management, it does not inherently involve processing (e.g., analysis, conversion, or interpretation).","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>11","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"The part labelled X in Figure 1 is called","images":["data:image/jpeg;base64,"],"options":{"A":"analysis.","B":"evaluation.","C":"feedback.","D":"retreat."},"answer":"C","explanation":"The image shows a diagram labeled \"Figure 1: Information Cycle\" with blocks for \"Input,\" \"Decision making,\" and \"Output.\" There's a loop from \"Output\" back towards \"Input,\" with a block labeled \"X\" in the middle of this loop.    This cycle represents how information is processed and refined over time. After information is output, it's often evaluated, and the results of that evaluation (X) are fed back into the input stage to improve future decision-making or processing. This iterative process is characteristic of systems that learn or adapt.    Therefore, the part labeled X, representing the flow from output back to input to influence subsequent processes, is best described as feedback.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>12","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"Which one of the following gadgets allows the transmission of both visual and audio information?","images":[],"options":{"A":"Facsimile","B":"Radio","C":"Television","D":"Walkie-Talkie"},"answer":"C","explanation":"Television is the only gadget among the options that transmits both visual (video) and audio (sound) information simultaneously. It combines:    Visual data: Images, videos, text (e.g., news broadcasts, movies).    Audio data: Soundtracks, dialogues, music.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>13","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"Use Figure 2 to answer questions 13 and 14.      The underlying technology in the network connection in Figure 2 is called","images":["data:image/jpeg;base64,"],"options":{"A":"Bluetooth.","B":"Ethernet.","C":"Laser Jet.","D":"Optical Fibre."},"answer":"A","explanation":"Since Figure 2 explicitly shows a Bluetooth network, the underlying technology is Bluetooth, a wireless standard for short-range data exchange (e.g., connecting phones to headphones).","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>14","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"Use Figure 2 to answer questions 13 and 14.    One limitation of the network type in Figure 2 is that","images":["data:image/jpeg;base64,"],"options":{"A":"cost of maintenance is high.","B":"distance covered is short.","C":"resources that can be shared are selective.","D":"weather can affect the rate of data sharing."},"answer":"B","explanation":"Bluetooth networks operate over short distances, typically up to 10 meters (33 feet) for most devices, though some can go up to 100 meters with reduced data rate.    This limited range is a key limitation of Bluetooth when compared to other wireless technologies like Wi-Fi.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>15","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"Use Figure 3 to answer questions 15 and 16.      The interface in Figure 3 is used for","images":["data:image/jpeg;base64,"],"options":{"A":"creating new sites.","B":"creating portable documents.","C":"sending and receiving e-mails.","D":"sending and receiving SMS."},"answer":"C","explanation":"Email interfaces (e.g., Gmail, Outlook) commonly feature:    - A search bar (to find emails).    - A placeholder (e.g., \"Search mail\" or \"Compose new email\").    Thererefore the interface in Figure 3 is used for sending and receiving e-mails.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>16","subject":"Data Processing","year":"2025","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"Use Figure 3 to answer questions 15 and 16.    The part labelled III in Figure 3 is used for","images":["data:image/jpeg;base64,"],"options":{"A":"keeping draft portable documents.","B":"keeping unfinished sites.","C":"saving unsent e-mails.","D":"saving unsent SMS."},"answer":"C","explanation":"In email applications:    The \"Drafts\" folder is used to store email messages that have been written but not yet sent.    This allows users to return later to complete or send them.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>17","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : SAFETY MEASURES","question":"What happens when the Shift key is pressed while deleting a file from the computer in Windows? The file is","images":[],"options":{"A":"uninstalled from the computer.","B":"permanently deleted from the computer.","C":"deleted and sent to the Recycle Bin.","D":"deleted and kept in the clipboard."},"answer":"B","explanation":"In Windows, when you delete a file:    Pressing Delete alone sends the file to the Recycle Bin (you can restore it later).    Pressing Shift + Delete bypasses the Recycle Bin and permanently deletes the file. It cannot be restored unless you use special recovery software.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>18","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"Figure 4 is a full set of page formatting options captured from MS Word application.  Use it to answer questions 18 and 19.      A user who was typing a document in portrait orientation decided to complete the next few pages in landscape orientation. Which one of the following options illustrates the correct order of steps the user must follow by clicking on the labelled parts to achieve this?","images":["data:image/jpeg;base64,"],"options":{"A":"I, III and V","B":"I, IV and V","C":"II, III and V","D":"II, IV and V"},"answer":"D","explanation":"To switch from portrait to landscape orientation for specific pages in MS Word:    1. Step II (Landscape Orientation):    Click the Landscape option under \"Orientation\" to change the layout.    2. Step IV (Apply to Whole Document):    In the \"Apply to\" dropdown, select Whole document to ensure consistency or This section if using section breaks.    3. Step V (OK):    Confirm the changes by clicking OK.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>19","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"Figure 4 is a full set of page formatting options captured from MS Word application.  Use it to answer questions 18 and 19.    Which one of these options gives the correct order of steps to revert to portrait orientation after typing in landscape orientation for a while?","images":["data:image/jpeg;base64,"],"options":{"A":"I, III and V","B":"I, IV and V","C":"II, III and V","D":"II, IV and V"},"answer":"B","explanation":"To revert from landscape to portrait orientation in MS Word:    1. Step I (Portrait Orientation):    Click the Portrait option under \"Orientation\" to switch back to the default vertical layout.    2. Step IV (Apply to Whole Document):    Select Whole document (or \"This section\" if using section breaks) to ensure the change applies to all pages.    3. Step V (OK):    Confirm the action by clicking OK.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>20","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"What happens when a user clicks on the Microsoft Excel menu bar icon shown in Figure 5?","images":["data:image/jpeg;base64,"],"options":{"A":"A copy of the selection is put on the clipboard","B":"A label that spans multiple columns is created","C":"Content on the clipboard is added to the insertion point","D":"Selected range of cells is quickly converted to a table with its own style"},"answer":"C","explanation":"The image in Figure 5 shows an icon that typically represents the \"Paste\" function in Microsoft Excel (and many other Windows applications). It looks like a clipboard with a document or sheet of paper being \"pasted\" onto it.    Therefore, the icon shown in Figure 5, which depicts a clipboard with a document, represents the Paste action.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>21","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"To add a new row above EKITI on the MS Excel interface shown in Figure 6, the user would right-click on","images":["data:image/jpeg;base64,"],"options":{"A":"cell A5 and then click on insert.","B":"cell A6 and then click on insert.","C":"row 5 and then click on insert.","D":"row 6 and then click on insert."},"answer":"D","explanation":"Since EKITI is in cell A6, and you want to add a new row above EKITI , you need to insert a row at row 6, which will push EKITI down.    To do that in MS Excel:    You right-click on row 6, and then select Insert.    This inserts a new row above row 6, moving EKITI to row 7.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>22","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"Which one of the following points is not considered when designing a database in Microsoft Access? Determine","images":[],"options":{"A":"how forms will be used.","B":"how tables will be related.","C":"the data needed.","D":"the purpose of the database."},"answer":"A","explanation":"When designing a database in Microsoft Access, the primary focus is on structural and functional requirements, not interface tools like forms. Key considerations include:    1. Purpose of the database \u2192 Defines the scope and goals (e.g., inventory tracking).    2. Data needed \u2192 Identifies tables/fields (e.g., ProductID, ProductName).    3. Table relationships \u2192 Establishes links (e.g., one-to-many between Customers and Orders).","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>23","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"Tables in Microsoft Access are created using the following methods except","images":[],"options":{"A":"Datasheet view.","B":"Design view.","C":"Table insertion.","D":"Table wizard."},"answer":"C","explanation":"In Microsoft Access, tables can be created using the following methods:    1. Datasheet View: Start entering data directly, and Access generates a table structure automatically.    2. Design View: Manually define fields, data types, and properties (most precise method).    3. Table Wizard: Use pre-built templates to create tables quickly.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>24","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"The keyboard shortcut for adding a new slide to Microsoft PowerPoint application is","images":[],"options":{"A":"Ctrl + H.","B":"Ctrl + M.","C":"Alt + H.","D":"Alt + M."},"answer":"B","explanation":"In Microsoft PowerPoint, the keyboard shortcut Ctrl + M quickly adds a new slide to your presentation. This shortcut works in all recent versions of PowerPoint (2010, 2013, 2016, 2019, 2021, 365).","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>25","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"An example of web design software is","images":[],"options":{"A":"CSS.","B":"MS Outlook.","C":"MS Publisher.","D":"SPSS."},"answer":"C","explanation":"MS Publisher is a desktop publishing application that can also be used to design simple websites or web pages.    CSS is a style sheet language, not a software.    MS Outlook is an email client.    SPSS is used for statistical analysis.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>26","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES","question":"The part labelled VII in Figure 7 is used to","images":["data:image/jpeg;base64,"],"options":{"A":"shape objects.","B":"select and transform objects.","C":"draw lines and curves.","D":"create texts."},"answer":"D","explanation":"In CorelDRAW, the Text Tool is used to create and edit text within your design. It is represented by the letter \"A\" and is often located in the toolbox on the left side of the interface","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>27","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The erratic movement of the mouse pointer is usually caused by","images":[],"options":{"A":"bad connection.","B":"dirty mouse ball.","C":"driver error.","D":"hardware failure."},"answer":"B","explanation":"In older mechanical mice (ball-type), erratic pointer movement is commonly caused by a dirty mouse ball or buildup of dirt on the rollers inside the mouse. Cleaning the mouse ball usually resolves the issue.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>28","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The suitable method of removing particles from the keyboard is by","images":[],"options":{"A":"cleaning with dripping wet cloth.","B":"cleaning with iron brush.","C":"using compressed air.","D":"using hot air."},"answer":"C","explanation":"Compressed air is the safest and most effective method to remove dust and particles from between the keys of a keyboard without causing damage. It blows debris out from hard-to-reach areas without needing to disassemble the keyboard.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>29","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : SAFETY MEASURES","question":"Which one of the following statements is true about preventing phishing?","images":[],"options":{"A":"Ensure that antivirus is updated regularly","B":"Do not click on links in e-mails from unknown sources","C":"Do not download from untrusted sites","D":"Use a strong password at all times"},"answer":"B","explanation":"Phishing involves tricking users into clicking malicious links in fake emails that appear legitimate. Avoiding clicks on links from unknown or suspicious sources is a primary defense against phishing attacks.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>30","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER","question":"Preventative maintenance measures in the computer room include the following except","images":[],"options":{"A":"good ventilation.","B":"maintaining dust-free environments.","C":"proper illumination.","D":"the use of rugs on the floor."},"answer":"D","explanation":"Using rugs in a computer room is not recommended because they can accumulate static electricity and dust, both of which can damage computer equipment. On the other hand, good ventilation, dust-free environments, and proper lighting are all valid preventative maintenance measures.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>31","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER","question":"When cleaning the computer system, it is advisable to","images":[],"options":{"A":"restart the computer first.","B":"turn off the computer and disconnect from power source.","C":"use antiglare cover to protect the screen.","D":"use multimeter tester for earthing."},"answer":"B","explanation":"Before cleaning any computer system, it is essential to power it off and unplug it from the electrical source to prevent electric shock or damage to the system.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>32","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING","question":"A system analyst is a professional who","images":[],"options":{"A":"designs flowcharts.","B":"designs and implements new computer-based solutions.","C":"trains computer users on new solutions.","D":"writes complex computer programs."},"answer":"B","explanation":"A system analyst studies an organization's current systems and processes and designs new computer-based solutions to improve efficiency and effectiveness. They may also be involved in implementation and coordination with developers and users.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>33","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER VIRUS","question":"Which one of the following programs is not a type of virus?","images":[],"options":{"A":"Boot sector virus","B":"Logic bomb","C":"Polymorphic virus","D":"Trojan horse"},"answer":"D","explanation":"A Trojan horse (or simply \"Trojan\") is a type of malware that disguises itself as legitimate software or tricks users into installing it. Unlike viruses, Trojans do not self-replicate by infecting other files. They rely on deception to spread. Once installed, they can perform various malicious activities. This is a type of malware, but NOT a type of virus.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>34","subject":"Data Processing","year":"2025","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER VIRUS","question":"The computer virus accesses the user's computer and and waits for a trigger during the","images":[],"options":{"A":"dormant phase.","B":"execution phase.","C":"propagation phase.","D":"trigger phase."},"answer":"A","explanation":"In the dormant phase, the virus is present in the system but remains inactive and waits silently for a trigger event before executing its payload.","marks":"1","difficulty":"3"},{"id":"objective>Data Processing>2025>35","subject":"Data Processing","year":"2025","type":"Objective","topic":"DATA MANAGEMENT : RELATIONAL MODEL","question":"The SQL constraint used to ensure the accuracy and consistency of data in a relational database is called","images":[],"options":{"A":"default constraint.","B":"index constraint.","C":"integrity constraint.","D":"unique constraint."},"answer":"C","explanation":"Integrity constraints in SQL are rules applied to database tables to ensure:    1. Accuracy: Data meets predefined conditions (e.g., NOT NULL).    2. Consistency: Relationships between tables are valid (e.g., foreign keys).    Types of Integrity Constraints:    Entity Integrity: Primary keys (PRIMARY KEY) enforce unique, non-null rows.    Referential Integrity: Foreign keys (FOREIGN KEY) maintain valid links between tables.    Domain Integrity: Data type/format rules (e.g., CHECK, DEFAULT).","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>36","subject":"Data Processing","year":"2025","type":"Objective","topic":"DATA MANAGEMENT : RELATIONAL MODEL","question":"To create a one-to-one relationship in database, it is necessary that","images":[],"options":{"A":"both primary and foreign key fields should have multiple key index.","B":"both primary and foreign key fields should have unique key index.","C":"only the foreign key field should have a unique index.","D":"only the primary key field should have a unique index."},"answer":"B","explanation":"In a one-to-one relationship, each record in both tables must be unique and correspond to only one record in the other table. Therefore, both the primary key and foreign key fields must have unique constraints (unique indexes) to enforce this.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>37","subject":"Data Processing","year":"2025","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"An advantage of manual file over computer file is that","images":[],"options":{"A":"it is more efficient.","B":"it requires less storage space.","C":"risk of corrupted data is much less.","D":"speed of processing is high."},"answer":"C","explanation":"Manual files are physical records, so they cannot be corrupted by software errors or viruses like computer files can. However, they are generally less efficient, slower, and require more physical storage space compared to computer files.","marks":"1","difficulty":"1"},{"id":"objective>Data Processing>2025>38","subject":"Data Processing","year":"2025","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"A user observed that a certain file in a removable storage device changed to a shortcut icon. This implies that","images":[],"options":{"A":"the file is corrupt.","B":"the file is shared.","C":"the removable storage device is corrupt.","D":"there is a link to the file."},"answer":"D","explanation":"When a file changes to a shortcut icon, it means the original file is linked by a shortcut, not the actual file itself. Sometimes this happens if malware creates shortcuts instead of showing the real files, but fundamentally, a shortcut is a link pointing to the file's location.","marks":"1","difficulty":"2"},{"id":"objective>Data Processing>2025>39","subject":"Data Processing","year":"2025","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"The objectives to consider while designing a secure database application include the following except","images":[],"options":{"A":"simplicity.","B":"secrecy.","C":"integrity.","D":"availability."},"answer":"A","explanation":"When designing a secure database application, the main objectives typically focus on secrecy (confidentiality), integrity, and availability \u2014 often referred to as the CIA triad in security. Simplicity is not a core security objective, though it may be desirable for usability.","marks":"1","difficulty":"3"},{"id":"objective>Data Processing>2025>40","subject":"Data Processing","year":"2025","type":"Objective","topic":"DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES","question":"Which one of the following features is not an advantage of distributed database?","images":[],"options":{"A":"Better response","B":"Lower communication cost.","C":"Improved reliability.","D":"Need for complex software."},"answer":"D","explanation":"The need for complex software is actually a disadvantage of distributed databases, not an advantage. Distributed databases improve response time, reduce communication costs, and enhance reliability, but they require more complex software to manage data distribution and synchronization.","marks":"1","difficulty":"2"}];